import React, { useMemo } from 'react';
import type { UseVoucherListSelectionResult } from '../../hooks/useVoucherListSelection';
import {
  CatalogListGridFromSchema,
  type CatalogListGridFromSchemaProps,
  listVisibleFields,
  useCatalogUiSchema,
} from '../listUiSchema';
import type { CatalogUiSchema } from '../../types/catalogUiSchema';
import erp from '../../styles/erpPage.module.css';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
  voucherListRowMenuHintDismissStorageKey,
} from '../../utils/voucherListRowMenuHint';

export type WmsSchemaListGridProps<T extends { id: string }> = {
  catalogKind: string;
  testIdPrefix: string;
  rows: T[];
  page: number;
  pageSize: number;
  showTableLoading: boolean;
  emptyLabel: string;
  selection: UseVoucherListSelectionResult<T>;
  onRowDoubleClick?: (row: T) => void;
  onRowOpenActionMenu?: (payload: { row: T; x: number; y: number }) => void;
  viewMobile?: boolean;
  sampleRow?: Record<string, unknown> | null;
};

type RowMenuPayload<T> = { row: T; x: number; y: number };

export function WmsSchemaListGrid<T extends { id: string }>({
  catalogKind,
  testIdPrefix,
  rows,
  page,
  pageSize,
  showTableLoading,
  emptyLabel,
  selection,
  onRowDoubleClick,
  onRowOpenActionMenu,
  viewMobile = false,
  sampleRow: sampleRowProp,
}: WmsSchemaListGridProps<T>): React.ReactElement | null {
  const sampleRow = useMemo(
    () => sampleRowProp ?? (rows[0] ? (rows[0] as unknown as Record<string, unknown>) : null),
    [rows, sampleRowProp],
  );
  const { schema } = useCatalogUiSchema(catalogKind, { sampleRow });
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);

  const rowMenuHintMessage =
    onRowOpenActionMenu != null
      ? viewMobile
        ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
        : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP
      : undefined;

  if (!showTableLoading && rows.length === 0) {
    return (
      <div className={erp.empty} data-testid={`${testIdPrefix}-empty`}>
        <i className="fas fa-inbox" />
        <p>{emptyLabel}</p>
      </div>
    );
  }

  if (showTableLoading || listColumns.length === 0) return null;

  const gridProps: CatalogListGridFromSchemaProps<T>['gridProps'] = {};
  if (onRowOpenActionMenu) {
    gridProps.onRowOpenActionMenu = (payload: RowMenuPayload<T>) => onRowOpenActionMenu(payload);
    gridProps.rowMenuHintMessage = rowMenuHintMessage;
    gridProps.rowMenuHintDismissStorageKey = voucherListRowMenuHintDismissStorageKey(testIdPrefix);
    gridProps.enableRowMenuLongPress = viewMobile;
  }
  if (onRowDoubleClick) {
    gridProps.onRowDoubleClick = (row: T) => onRowDoubleClick(row);
  }

  return (
    <CatalogListGridFromSchema<T>
      testIdPrefix={testIdPrefix}
      rows={rows}
      page={page}
      pageSize={pageSize}
      columns={listColumns}
      schema={schema as CatalogUiSchema | null}
      selection={selection}
      getRowId={r => r.id}
      gridProps={Object.keys(gridProps).length > 0 ? gridProps : undefined}
    />
  );
}
